--select * from customer;
--select * from drinks;
--select * from bar order by bar.date;


drop function if exists next;
create function next(hour numeric)
returns integer 
language plpgsql AS $$
BEGIN
	if hour = 23 then return 0;
	else return hour + 1; 
	end if;
END$$;


with recursive
cust_hours as(
	select extract(hour from date) as hour, customer, drinks from bar
), --select * from cust_hours
one_hours(hour, customer, all_drinks) as(
	select hour, customer, coalesce(sum(drinks), 0) from cust_hours
	group by hour, customer 
), --select * from one_hours
dp(hour, customer, adeq) as(
	select 21, one_hours.customer, greatest(0, one_hours.all_drinks - 1) from one_hours 
	where one_hours.hour = 21
	union all 
	
	select next(h1.hour), h1.customer, greatest(0, h1.adeq + h2.all_drinks - 1)
	from dp as h1
	join one_hours as h2 on (h1.customer = h2.customer)
							and
							(next(h1.hour) = h2.hour)
	
)select customer.name, dp.customer, dp.adeq from dp
join customer on customer.id = dp.customer 
where dp.hour = 5
order by adeq desc



	
	



